#include<bits/stdc++.h>
using namespace std;
int b[41],p[41],a[1000010];
const int mod=1e9+7;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&a[i]);
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        int t=(i&(-i));
        for(int j=1,k=1,l=i;k<=t;j++,k*=2,l/=2)
        {
            b[j]*=2;
            b[j]-=b[j+1];
            if(p[j]!=m&&a[p[j]+1]==l)
            {
                b[j]++;
                p[j]++;
            }
            b[j]=(b[j]%mod+mod)%mod;
        }
        if(i==n-1)
        {
            ans-=b[1];
        }
        if(i==n)
        {
            ans+=b[1];
            ans=(ans%mod+mod)%mod;
        }
    }
    printf("%d",ans);
    return 0;
}
